## Test: `apps/client/src/dev/__tests__/playground-registry.test.ts`

Create unit tests:

```typescript
import { describe, it, expect } from 'vitest';
import {
  PLAYGROUND_REGISTRY,
  TOKENS_SECTIONS,
  COMPONENTS_SECTIONS,
  CHAT_SECTIONS,
} from '../playground-registry';

describe('playground-registry', () => {
  it('has no duplicate section IDs across the full registry', () => {
    const ids = PLAYGROUND_REGISTRY.map((s) => s.id);
    const unique = new Set(ids);
    expect(unique.size).toBe(ids.length);
  });

  it('all IDs match the anchor generation pattern (lowercase, dashes, no spaces)', () => {
    for (const section of PLAYGROUND_REGISTRY) {
      expect(section.id).toMatch(/^[a-z0-9&\u2014-]+$/);
      expect(section.id).not.toMatch(/\s/);
    }
  });

  it('all sections have a valid page assignment', () => {
    const validPages = new Set(['overview', 'tokens', 'components', 'chat']);
    for (const section of PLAYGROUND_REGISTRY) {
      expect(validPages.has(section.page)).toBe(true);
