Create the `TocSidebar` component and integrate it into all three page components (ComponentsPage, ChatPage, TokensPage) with the scrollspy hook.

## Implementation

### 1. Create `apps/client/src/dev/TocSidebar.tsx`

```typescript
import { cn } from '@/layers/shared/lib';
import { ScrollArea } from '@/layers/shared/ui';
import type { PlaygroundSection } from './playground-registry';

interface TocSidebarProps {
  sections: PlaygroundSection[];
  activeId: string | null;
}

/** Sticky right-side table of contents with scrollspy active highlighting. */
export function TocSidebar({ sections, activeId }: TocSidebarProps) {
  return (
    <aside className="hidden w-48 shrink-0 xl:block">
      <nav className="sticky top-12">
        <p className="mb-2 text-xs font-medium text-muted-foreground">
          On this page
        </p>
        <ScrollArea className="max-h-[calc(100dvh-8rem)]">
          <ul className="space-y-0.5">
            {sections.map((section) => (
              <li key={section.id}>
                <a
                  href={`#${section.id}`}
                  onClick={(e) => {
                    e.preventDefault();
                    document.getElementById(section.id)?.scrollIntoView({
                      behavior: 'smooth',
                      block: 'start',
                    });
                    // Update URL hash without scroll jump
                    history.replaceState(null, '', `#${section.id}`);
                  }}
                  className={cn(
                    'block truncate rounded-md px-2 py-1 text-xs transition-colors',
                    activeId === section.id
                      ? 'bg-accent font-medium text-accent-foreground'
                      : 'text-muted-foreground hover:text-foreground',
                  )}
                >
                  {section.title}
                </a>
              </li>
            ))}
          </ul>
        </ScrollArea>
      </nav>
    </aside>
  );
}
```

Key design decisions:
- Hidden below `xl` (1280px) breakpoint via `hidden xl:block` -- dev tool, no need for mobile TOC
- `sticky top-12` keeps the TOC fixed while the main content scrolls
- `ScrollArea` with `max-h-[calc(100dvh-8rem)]` handles long TOCs with a scrollbar
- Active item gets `bg-accent font-medium text-accent-foreground` styling
- `history.replaceState` updates the URL hash without causing a scroll jump
- `truncate` on links prevents long section names from breaking the 48-unit width

