Create the `PlaygroundSearch` component that provides Cmd+K fuzzy search across all playground sections.

## Implementation

### Create `apps/client/src/dev/PlaygroundSearch.tsx`

```typescript
import {
  Command,
  CommandInput,
  CommandList,
  CommandEmpty,
  CommandGroup,
  CommandItem,
  CommandShortcut,
  ResponsiveDialog,
  ResponsiveDialogContent,
} from '@/layers/shared/ui';
import { PLAYGROUND_REGISTRY, type Page, type PlaygroundSection } from './playground-registry';

interface PlaygroundSearchProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onNavigate: (page: Page, sectionId: string) => void;
}

/** Map page keys to human-readable group headings. */
function pageLabel(page: string): string {
  switch (page) {
    case 'tokens': return 'Design Tokens';
    case 'components': return 'Components';
    case 'chat': return 'Chat UI';
    default: return page;
  }
}

/** Group sections by their page for display in command groups. */
function groupByPage(sections: PlaygroundSection[]): Record<string, PlaygroundSection[]> {
  const grouped: Record<string, PlaygroundSection[]> = {};
  for (const section of sections) {
    if (!grouped[section.page]) grouped[section.page] = [];
    grouped[section.page].push(section);
  }
  return grouped;
}

/** Cmd+K search dialog for navigating to any playground section. */
export function PlaygroundSearch({ open, onOpenChange, onNavigate }: PlaygroundSearchProps) {
  const grouped = groupByPage(PLAYGROUND_REGISTRY);

  return (
    <ResponsiveDialog open={open} onOpenChange={onOpenChange}>
      <ResponsiveDialogContent className="p-0" hideClose>
        <Command className="rounded-lg">
          <CommandInput placeholder="Search components and tokens..." />
          <CommandList>
            <CommandEmpty>No results found.</CommandEmpty>
            {Object.entries(grouped).map(([page, sections]) => (
              <CommandGroup key={page} heading={pageLabel(page)}>
                {sections.map((section) => (
                  <CommandItem
                    key={section.id}
                    value={section.title}
                    keywords={section.keywords}
                    onSelect={() => {
                      onOpenChange(false);
                      onNavigate(section.page, section.id);
                    }}
                  >
                    {section.title}
                    <CommandShortcut>{section.category}</CommandShortcut>
                  </CommandItem>
                ))}
              </CommandGroup>
            ))}
          </CommandList>
        </Command>
      </ResponsiveDialogContent>
    </ResponsiveDialog>
  );
}
```

Key design decisions:
- Uses `ResponsiveDialog` + `Command` from shadcn/ui (both already available)
- `hideClose` on `ResponsiveDialogContent` since Escape and outside click already close it
- `keywords` prop on `CommandItem` enables fuzzy matching beyond just the title (e.g., typing "btn" matches "Button")
- `CommandShortcut` displays the category on the right side of each item
- Groups are ordered by page: tokens, components, chat (matching registry order)
- `cmdk`'s built-in filter handles fuzzy matching -- sufficient for ~50 items

